+  assert(_current_depth < _max_depth, "invariant");
+  _current_chunkindex = item.chunkindex;
+  assert(_current_chunkindex >= 0, "invariant");
+
+  _current_pointee = _current_ref.dereference();
+
+  return true;
+}
